import { describe, expect, it } from 'vitest';

import {
  BANDWIDTH_TRIHEXENNEON,
  BANDWIDTH_TRITON,
  CarrierMediumPipeline,
  analyzeCarrierMedium,
  carrierFiberForPosition,
  classifyCarrierStep,
  projectCarrierPosition,
  quantizeUnitToCarrierStep,
} from '../src/index';

describe('CarrierMediumPipeline carrier arithmetic', () => {
  it('quantizes unit samples into source carrier step origins', () => {
    expect(quantizeUnitToCarrierStep(0, BANDWIDTH_TRIHEXENNEON)).toBe(0);
    expect(
      quantizeUnitToCarrierStep(
        2 / BANDWIDTH_TRIHEXENNEON,
        BANDWIDTH_TRIHEXENNEON,
      ),
    ).toBe(2);
    expect(quantizeUnitToCarrierStep(1, BANDWIDTH_TRIHEXENNEON)).toBe(53);
  });

  it('projects 54 high-band positions into Triton 18-position fibers', () => {
    expect(projectCarrierPosition(0, 54, 3)).toBe(0);
    expect(projectCarrierPosition(17, 54, 3)).toBe(0);
    expect(projectCarrierPosition(18, 54, 3)).toBe(1);
    expect(projectCarrierPosition(53, 54, 3)).toBe(2);

    expect(carrierFiberForPosition(17, 54, 3)).toEqual({
      sourceBandwidth: 54,
      observerBandwidth: 3,
      lowerPosition: 0,
      start: 0,
      endExclusive: 18,
      multiplicity: 18,
    });
  });

  it('reads the same +1 as evolution at Triton and resolution at Trihexenneon', () => {
    const triton = classifyCarrierStep(2, 54, 3);
    const trihexenneon = classifyCarrierStep(2, 54, 54);

    expect(triton.reading).toBe('evolution');
    expect(triton.buleCost).toBe(1);
    expect(triton.silenceOfUnderBandwidth).toBe(true);
    expect(triton.fiber.multiplicity).toBe(18);
    expect(trihexenneon.reading).toBe('resolution');
    expect(trihexenneon.buleCost).toBe(1);
    expect(trihexenneon.silenceOfUnderBandwidth).toBe(false);
  });
});

describe('CarrierMediumPipeline generic analysis', () => {
  it('analyzes arbitrary unit-valued carrier cells', () => {
    const pipeline = new CarrierMediumPipeline({
      sourceBandwidth: 54,
      observerBandwidths: [BANDWIDTH_TRITON, BANDWIDTH_TRIHEXENNEON],
    });
    const analysis = pipeline.analyze({
      cells: [
        { id: 'edge-a', unitValue: 2 / 54, metadata: { domain: 'image' } },
        { id: 'edge-b', unitValue: 53 / 54, metadata: { domain: 'audio' } },
      ],
    });

    expect(analysis.cells).toHaveLength(2);
    expect(analysis.cells[0]!.id).toBe('edge-a');
    expect(analysis.cells[0]!.stepOrigin).toBe(2);
    expect(analysis.cells[0]!.readings.map((r) => r.reading)).toEqual([
      'evolution',
      'resolution',
    ]);
    expect(analysis.cells[1]!.stepOrigin).toBe(53);
    expect(analysis.cells[1]!.readings.map((r) => r.reading)).toEqual([
      'evolution',
      'evolution',
    ]);
  });

  it('keeps Bule +1 cost invariant across bandwidths', () => {
    const analysis = analyzeCarrierMedium({
      cells: [
        { unitValue: 0 },
        { unitValue: 2 / 54 },
        { unitValue: 17 / 54 },
        { unitValue: 1 },
      ],
    });

    expect(analysis.buleCostInvariantAcrossBandwidths).toBe(true);
    expect(analysis.summaries.map((summary) => summary.totalBuleCost)).toEqual([
      4,
      4,
      4,
    ]);
  });

  it('rejects invalid carrier settings and non-finite cells', () => {
    expect(() => new CarrierMediumPipeline({ observerBandwidths: [] })).toThrow(
      /observerBandwidths/,
    );
    const pipeline = new CarrierMediumPipeline();
    expect(() =>
      pipeline.analyze({ cells: [{ unitValue: Number.NaN }] }),
    ).toThrow(/unitValue/);
  });
});
